@font-face {
    font-family: 'Ahem';
    src: url('file:///Users/henryluo/Projects/lambda-test/layout/data/support/ahem3.ttf') format('truetype');
    font-weight: normal;
    font-style: normal;
}

.sample {
    border: solid 1px green;
    font-family: Ahem;
    font-size: 20px;
    height: 230px;
    line-height: 24px;
    writing-mode: vertical-rl;
}

.float {
    background: cyan;
    clear: none;
    float: left;
    height: 50px;
    width: 50px;
}

.mc {
    columns: 2;
    direction: ltr;
    height: 500px;
    writing-mode: vertical-rl;
}

.initial-letter::first-letter {
    initial-letter: 3 drop;
    color: lime;
    font-size: 100px;   /* should be ignored in rendering */
    line-height: 50px;  /* should be ignored in rendering */
}
